using System;

class Program
{
    static void Main(string[] args)
    {
        int count = 1;

        while (count <= 5)
        {
            if (count == 3)
            {
                count++;
                continue; // 3-ü atlayır
            }
            if (count == 5)
            {
                break; // Dövrü dayandırır
            }
            Console.WriteLine($"Rəqəm: {count}");
            count++;
        }
    }
}
// Output:
// Rəqəm: 1
// Rəqəm: 2
// Rəqəm: 4

